import React, { useState, useEffect } from "react";
import { List, Image, Space, Button, notification, Popconfirm } from "antd";

import "./index.css";

interface Props {
  historyLaunchGame: (info: any) => void;
}

const GameHistory: React.FC<Props> = ({ historyLaunchGame }) => {
  const [gameHistory, setGameHistory] = useState([]);
  const [api, contextHolder] = notification.useNotification();
  const getGameHistory = async () => {
    const _gameHistory: any = await window.electronAPI.readGameHistory();
    setGameHistory(_gameHistory);
  };

  useEffect(() => {
    getGameHistory();
  }, []);

  const openGameDir = async (gamePath: string) => {
    const result: any = await window.electronAPI.openGameDir(gamePath);
    if (!result.success) {
      api.error({
        message: result?.message,
        description: "",
      });
    }
  };

  const handleDeleteHistory = async (gamePath: string) => {
    const result: any = await window.electronAPI.deleteGameHistory(gamePath);
    console.log(result);
    if (result.success) {
      api.success({
        message: "删除成功",
        description: "",
      });
      getGameHistory();
    } else {
      api.error({
        message: "错误",
        description: result?.message,
      });
    }
  };
  return (
    <div>
      {contextHolder}
      <List
        header={<div>这里保存着你使用该工具启动过的游戏</div>}
        bordered
        dataSource={gameHistory}
        renderItem={(item: any) => (
          <List.Item>
            <Space size={"middle"}>
              <Image
                width={200}
                src={item?.img}
                fallback="data:image/png;base64,"
                className="item-img"
                preview={false}
              />
              <Space
                direction="vertical"
                size="middle"
                style={{ display: "flex" }}
              >
                <div>游戏名称:{item.title}</div>
                <div>游戏路径:{item.gamePath}</div>
                <div>第一次运行:{item.firstPlayed}</div>
                <div>最后一次运行:{item.lastPlayed}</div>
                <Space>
                  <Button onClick={() => historyLaunchGame(item)}>
                    启动游戏
                  </Button>
                  <Button onClick={() => openGameDir(item.gamePath)}>
                    打开游戏位置
                  </Button>
                  <Popconfirm
                    title="删除记录"
                    description="你确定要删除这条游玩记录吗?"
                    onConfirm={() => handleDeleteHistory(item.gamePath)}
                    onCancel={() => {}}
                    okText="Yes"
                    cancelText="No"
                  >
                    <Button danger>从记录中删除</Button>
                  </Popconfirm>
                </Space>
              </Space>
            </Space>
          </List.Item>
        )}
      />
    </div>
  );
};

export default GameHistory;
